@import (reference) '../../style/themes/default.less';

.am-tips-plain-favorite {
  position: fixed;
  bottom: 50px;
  left: 50px;
  // padding: 7px 10px;
  box-sizing: border-box;
  font-size: @font-size-subtitle;
  font-size: var(--am-tips-plain-font-size, @font-size-subtitle);

  &-wrap {
    position: relative;
    background: @color-fill-grey-dark;
    background: var(--am-tips-plain-bg-color, @color-fill-grey-dark);
    box-shadow: 0 4px 10px 0 rgba(51, 51, 51, 0.20);
    border-radius: @corner-radius-lg;
    border-radius: var(--am-tips-plain-border-radius, @corner-radius-lg);
    color: @color-text-base;
    color: var(--am-tips-plain-text-color, @color-text-base);
    padding: 6px @h-spacing-large;
    padding: 6px var(--am-tips-plain-padding, @h-spacing-large);
    min-height: 10px;
  }

  &-content {
    line-height: @line-height-paragraph;
    line-height: var(--am-tips-plain-line-height, @line-height-paragraph);
    overflow: hidden;
    // height: 12px;
  }

  &-action:active {
    background: @color-fill-grey-dark;
    background: var(--am-tips-plain-bg-color, @color-fill-grey-dark);
  }

  &-wrap::before {
    content: '';
    position: absolute;
    bottom: -8px;
    left: 50%;
    margin-left: -8px;
    border-left: 8px solid transparent;
    border-right: 8px solid transparent;
    border-top: 9px solid @color-fill-grey-dark;
    border-top: 9px solid var(--am-tips-plain-bg-color, @color-fill-grey-dark);
  }
}

@import (reference) "../style/themes/default.less";

.am-switch {
  .checkbox {
    width: 102 * @pixelSize;
    height: 62 * @pixelSize;
    border-radius: @corner-radius-circle;
    border-radius: var(--am-switch-corner-radius, @corner-radius-circle);
  }
  .checkbox:after {
    left: 4 * @pixelSize;
    top: 4 * @pixelSize;
    width: 54 * @pixelSize;
    height: 54 * @pixelSize;
    border-radius: @corner-radius-circle;
    border-radius: var(--am-switch-float-corner-radius, @corner-radius-circle);
  }
  .checkbox:before {
    left: 4 * @pixelSize;
    top: 4 * @pixelSize;
    width: 94 * @pixelSize;
    height: 54 * @pixelSize;
    border-radius: @corner-radius-circle;
    border-radius: var(--am-switch-corner-radius, @corner-radius-circle);
  }
  &.a-switch-android .checkbox {
    width: 144 * @pixelSize;
    height: 46 * @pixelSize;
    border-radius: 6 * @pixelSize;
  }
  &.a-switch-android .checkbox:after {
    width: 70 * @pixelSize;
    height: 42 * @pixelSize;
    border-radius: 4 * @pixelSize;
    left: 2 * @pixelSize;
    top: 2 * @pixelSize;
  }
  .a-switch-checkbox.a-switch-checkbox:checked ~ .checkbox {
    background: @color-fill-primary;
    background: var(--am-switch-background, @color-fill-primary);
  }
  .a-switch-checkbox.a-switch-checkbox:checked ~ .checkbox::after {
    transform: translateX(40 * @pixelSize);
  }
  &.a-switch-android .a-switch-checkbox.a-switch-checkbox:checked ~ .checkbox::after {
    transform: translateX(70 * @pixelSize);
  }
}

// Cascader
// --------------------------------------------------
@prefix-cls-carousel: e("@{prefix-cls}-carousel");


.@{prefix-cls-carousel} {
  position: relative;
  overflow: hidden;

  &-content {
    position: relative;

    height: 100%;
  }
  &-indicators {
    position: absolute;
    bottom: 0;
    z-index: 99;

    padding: 1rem;
  }
  &-center {
    left: 50%;

    transform: translateX(-50%);
  }
  &-left {
    left: 0;
  }
  &-right {
    right: 0;
  }
  &-indicator-icon {
    border: 1px solid rgba(255, 255, 255, .6);
    width: 9px;
    height: 9px;
    display: inline-block;
    border-radius: 50%;
    margin: 0 5px;
    cursor: pointer;
  }
  .carousel-indicator-active {
    background: #cfcccc;
    border-color: #cfcccc;
    opacity: 0.6;
  }
  &-btn {
    position: absolute;
    top: 50%;
    z-index: 99;

    transform: translateY(-50%);
    cursor: pointer;
    background-color: #000;
    transition: opacity .3s;
    opacity: .3;
  }
  &-btn:hover {
    opacity: .5;
  }
  &-left-btn {
    left: 0;

    padding: 1rem .5rem .75rem .8rem;
  }
  &-right-btn {
    right: 0;

    padding: 1rem .8rem .75rem .5rem;
  }
  &-icon {
    display: inline-block;
    width: 20px;
    height: 20px;
    border-left: 2px solid #fff;
    border-bottom: 2px solid #fff;
  }
  &-icon-left {
    transform: rotate(45deg);
  }
  &-icon-right {
    transform: rotate(-135deg);
  }
  &-item {
    float: left;
    width: 100%;
    height: 100%;
    text-align: center;
    > a, img , > a > img {
      // max-width: 100%;
    }
  }
}

//
// Thumbnails
// --------------------------------------------------
//** Padding around the thumbnail image
@thumbnail-padding:           4px;
//** Thumbnail background color
@thumbnail-bg:                @body-bg;
//** Thumbnail border color
@thumbnail-border:            #ddd;
//** Thumbnail border radius
@thumbnail-border-radius:     @border-radius-base;

//** Custom text color for thumbnail captions
@thumbnail-caption-color:     @text-color;
//** Padding around the thumbnail caption
@thumbnail-caption-padding:   9px;

// Mixin and adjust the regular image class
.thumbnail {
  display: block;
  padding: @thumbnail-padding;
  margin-bottom: @line-height-computed;
  line-height: @line-height-base;
  background-color: @thumbnail-bg;
  border: 1px solid @thumbnail-border;
  border-radius: @thumbnail-border-radius;
  .transition(border .2s ease-in-out);

  > img,
  a > img {
    &:extend(.img-responsive);
    margin-left: auto;
    margin-right: auto;
  }

  // Add a hover state for linked versions only
  a&:hover,
  a&:focus,
  a&.active {
    border-color: @link-color;
  }

  // Image captions
  .caption {
    padding: @thumbnail-caption-padding;
    color: @thumbnail-caption-color;
  }
}

