// zombieJ: 简单兜底，由于现在只有首页在用，所以不封装了

.root {
  background: transparent;

  :global {
    .__dumi-default-dark {
      display: none;
    }

    // ==================== Logo ====================
    .__dumi-default-navbar-logo {
      img {
        filter: brightness(100);
      }
    }

    .title,
    .version {
      color: #fff;
    }

    .version {
      opacity: 0.65;
    }

    // =================== Search ===================
    .__dumi-default-search-input {
      background: rgba(255, 255, 255, 0.2) !important;
      color: #fff;

      &::placeholder {
        color: rgba(255, 255, 255, 0.65);
      }
    }

    // =================== Navbar ===================
    .right-part {
      nav {
        > span > a {
          color: #fff;
          opacity: 0.8;
          transition: all 0.3s;

          &::after {
            content: '';
            position: absolute;
            height: 3px;
            left: 0;
            right: 0;
            top: 0;
            background: #fff;
            opacity: 0;
            transition: all 0.3s;
          }

          &:hover {
            color: #fff;
            opacity: 1;

            &::after {
              opacity: 1;
            }
          }
        }
      }
    }

    .__dumi-default-navbar-tool {
      .__dumi-default-locale-select {
        border-radius: 4px;
        border-color: #fff;
        background: rgba(255, 255, 255, 0.2);
        opacity: 0.8;
        transition: all 0.3s;

        &:hover {
          opacity: 1;
        }

        > a {
          color: #fff;
        }
      }
    }
  }
}

@class-prefix-space: ~'adm-space';

.@{class-prefix-space}-item {
  flex: none;
}

.@{class-prefix-space} {
  display: inline-flex;
  --gap: 8px;
  --gap-vertical: var(--gap);
  --gap-horizontal: var(--gap);
  &-vertical {
    flex-direction: column;
    > .@{class-prefix-space}-item {
      margin-bottom: var(--gap-vertical);
      &:last-child {
        margin-bottom: 0;
      }
    }
  }
  &-horizontal {
    flex-direction: row;
    > .@{class-prefix-space}-item {
      margin-right: var(--gap-horizontal);
      &:last-child {
        margin-right: 0;
      }
    }
    &.@{class-prefix-space}-wrap {
      flex-wrap: wrap;
      margin-bottom: calc(var(--gap-vertical) * -1);
      > .@{class-prefix-space}-item {
        padding-bottom: var(--gap-vertical);
      }
    }
  }
  &.@{class-prefix-space}-block {
    display: flex;
  }
  &-align {
    &-center {
      align-items: center;
    }
    &-start {
      align-items: flex-start;
    }
    &-end {
      align-items: flex-end;
    }
    &-baseline {
      align-items: baseline;
    }
  }
  &-justify {
    &-center {
      justify-content: center;
    }
    &-start {
      justify-content: flex-start;
    }
    &-end {
      justify-content: flex-end;
    }
    &-between {
      justify-content: space-between;
    }
    &-around {
      justify-content: space-around;
    }
    &-evenly {
      justify-content: space-evenly;
    }
    &-stretch {
      justify-content: stretch;
    }
  }
}

@class-prefix-result: ~'adm-result';

.@{class-prefix-result} {
  padding: 32px 12px;
  background-color: var(--adm-color-background);

  &-icon {
    box-sizing: border-box;
    width: 64px;
    height: 64px;
    margin: 0 auto 20px auto;
    padding: 6px;

    .antd-mobile-icon {
      font-size: 52px;
    }
  }

  &-title {
    color: var(--adm-color-text);
    font-size: var(--adm-font-size-10);
    line-height: 1.4;
    text-align: center;
  }

  &-description {
    margin-top: 8px;
    color: var(--adm-color-weak);
    font-size: var(--adm-font-size-main);
    line-height: 1.4;
    text-align: center;
  }
}

.@{class-prefix-result}-success {
  .@{class-prefix-result}-icon {
    .antd-mobile-icon {
      color: var(--adm-color-primary);
    }
  }
}

.@{class-prefix-result}-error {
  .@{class-prefix-result}-icon {
    .antd-mobile-icon {
      color: var(--adm-color-danger);
    }
  }
}

.@{class-prefix-result}-info {
  .@{class-prefix-result}-icon {
    .antd-mobile-icon {
      color: var(--adm-color-primary);
    }
  }
}

.@{class-prefix-result}-waiting {
  .@{class-prefix-result}-icon {
    .antd-mobile-icon {
      color: var(--adm-color-success);
    }
  }
}

.@{class-prefix-result}-warning {
  .@{class-prefix-result}-icon {
    .antd-mobile-icon {
      color: var(--adm-color-warning);
    }
  }
}

@class-prefix-stepper: ~'adm-stepper';

.@{class-prefix-stepper} {
  --height: 28px;
  --input-width: 44px;
  --input-font-size: var(--adm-font-size-main);
  --input-font-color: var(--adm-color-text);
  --input-background-color: var(--adm-color-fill-content);
  --border-radius: 2px;
  --border: none;
  --border-inner: solid 2px transparent;
  --active-border: var(--border);
  --button-font-size: var(--adm-font-size-7);
  --button-text-color: var(--adm-color-primary);
  --button-background-color: var(--adm-color-fill-content);
  --button-width: var(--height);

  display: flex;
  align-items: center;
  box-sizing: border-box;
  position: relative;
  overflow: hidden;
  width: calc(var(--input-width) + 2 * var(--button-width));
  border: var(--border);
  border-radius: var(--border-radius);
  &-active {
    border: var(--active-border);
  }

  &-middle {
    flex: 1;
    border-left: var(--border-inner);
    border-right: var(--border-inner);
  }

  .@{class-prefix-stepper}-input {
    height: var(--height);
    --background-color: var(--input-background-color);
    --font-size: var(--input-font-size);
    --color: var(--input-font-color);
    --text-align: center;
  }

  &-minus,
  &-plus {
    width: var(--button-width);
    height: var(--height);
    padding: 0;
    color: var(--button-text-color);
    background-color: var(--button-background-color);
    font-size: var(--button-font-size);
    --border-width: 0;

    &:disabled {
      color: var(--adm-color-weak);
    }
    svg {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
    }
  }

  &-minus {
    border-radius: 0;
  }

  &-plus {
    border-radius: 0;
  }
}

@import '~antd/es/style/themes/default.less';

@basicLayout-prefix-cls: ~'@{ant-prefix}-pro-basicLayout';
@pro-layout-header-height: 48px;

.@{basicLayout-prefix-cls} {
  // BFC
  display: flex;
  flex-direction: column;
  width: 100%;
  min-height: 100%;

  .@{ant-prefix}-layout-header {
    &.@{ant-prefix}-pro-fixed-header {
      position: fixed;
      top: 0;
    }
  }

  &-content {
    position: relative;
    margin: 24px;

    .@{ant-prefix}-pro-page-container {
      margin: -24px -24px 0;
    }

    &-disable-margin {
      margin: 0;

      .@{ant-prefix}-pro-page-container {
        margin: 0;
      }
    }
    > .@{ant-prefix}-layout {
      max-height: 100%;
    }
  }

  // children should support fixed
  .@{basicLayout-prefix-cls}-is-children.@{basicLayout-prefix-cls}-fix-siderbar {
    height: 100vh;
    overflow: hidden;
    transform: rotate(0);
  }

  .@{basicLayout-prefix-cls}-has-header {
    // tech-page-container
    .tech-page-container {
      height: calc(100vh - @pro-layout-header-height);
    }
    .@{basicLayout-prefix-cls}-is-children.@{basicLayout-prefix-cls}-has-header {
      .tech-page-container {
        height: calc(
          100vh - @pro-layout-header-height - @pro-layout-header-height;
        );
      }
      .@{basicLayout-prefix-cls}-is-children {
        min-height: calc(100vh - @pro-layout-header-height);
        &.@{basicLayout-prefix-cls}-fix-siderbar {
          height: calc(100vh - @pro-layout-header-height);
        }
      }
    }
  }
}

