.alert-dismissable,
.alert-dismissible {
  padding-right: (@alert-padding + 20);

  // Adjust close link position
  .close {
    position: relative;
    top: -2px;
    right: -21px;
    color: inherit;
  }
}

// Alternate styles
//
// Generate contextual modifier classes for colorizing the alert.

.alert-success {
  .alert-variant(@alert-success-bg; @alert-success-border; @alert-success-text);
}

.alert-info {
  .alert-variant(@alert-info-bg; @alert-info-border; @alert-info-text);
}

.alert-warning {
  .alert-variant(@alert-warning-bg; @alert-warning-border; @alert-warning-text);
}

.alert-danger {
  .alert-variant(@alert-danger-bg; @alert-danger-border; @alert-danger-text);
}

@import '@delon/theme/index';

.avatar-holder {
  margin-bottom: 24px;
  text-align: center;

  & > img {
    width: 104px;
    height: 104px;
    margin-bottom: 20px;
  }

  .name {
    margin-bottom: 4px;
    font-size: 20px;
    font-weight: 500;
    line-height: 28px;
    color: @heading-color;
  }
}

.detail {
  p {
    position: relative;
    margin-bottom: 8px;
    padding-left: 26px;

    &:last-child {
      margin-bottom: 0;
    }
  }

  i {
    position: absolute;
    top: 4px;
    left: 0;
    width: 14px;
    height: 14px;
    background: url('https://gw.alipayobjects.com/zos/rmsportal/pBjWzVAHnOOtAUvZmZfy.svg');

    &.title {
      background-position: 0 0;
    }

    &.group {
      background-position: 0 -22px;
    }

    &.address {
      background-position: 0 -44px;
    }
  }
}

.tags-title,
.team-title {
  margin-bottom: 12px;
  font-weight: 500;
  color: @heading-color;
}

.tags {
  ::ng-deep {
    .ant-tag {
      margin-bottom: 8px;
    }
  }
}

.team {
  ::ng-deep {
    .ant-avatar {
      margin-right: 12px;
    }
  }

  a {
    display: block;
    margin-bottom: 24px;
    color: @text-color;
    transition: color 0.3s;

    &:hover {
      color: @primary-color;
    }
  }
}

.tabs-card {
  ::ng-deep {
    .ant-card-head-title {
      padding: 0 16px;
    }
  }
}

@import '@delon/theme/index';

:host {
  display: block;
  padding-top: 24px;

  ::ng-deep {
    .main {
      overflow: auto;
      display: flex;
      width: 100%;
      padding-top: 16px;
      padding-bottom: 16px;
      background-color: #fff;
    }

    .menu {
      width: 224px;
      border-right: @border-width-base @border-style-base @border-color-split;

      .ant-menu-inline {
        border: none;
      }

      .ant-menu:not(.ant-menu-horizontal) .ant-menu-item-selected {
        font-weight: bold;
      }
    }

    .content {
      flex: 1;
      padding: 8px 40px;

      .title {
        margin-bottom: 12px;
        font-size: 20px;
        font-weight: 500;
        line-height: 28px;
        color: @heading-color;
      }

      .ant-list-split .ant-list-item:last-child {
        border-bottom: 1px solid #e8e8e8;
      }

      .ant-list-item {
        padding-top: 14px;
        padding-bottom: 14px;
      }
    }

    @media screen and (max-width: @mobile-max) {
      .main {
        flex-direction: column;

        .menu {
          width: 100%;
          border: none;
        }

        .content {
          padding: 40px;
        }
      }
    }
  }
}

[data-theme='dark'] {
  :host ::ng-deep {
    .main {
      background-color: #141414;
    }

    .content {
      .title {
        color: rgb(255 255 255 / 65%);
      }
    }

    .menu {
      border-right-color: #303030;
    }

    .content .ant-list-split .ant-list-item:last-child {
      border-bottom-color: #303030;
    }
  }
}
